SELECT a.id, a.hid, a.recycle, a.astatus, a.mch_id, a.free_or_not, a.user_id, a.type, a.add_time, a.expiry_time, a.type, a.NAME, a.activity_type, a.money, a.discount, a.mobile, a.duserid, a.sNo, a.user_name, a.headimgurl, a.STATUS FROM ( SELECT DISTINCT a.id, a.hid, a.recycle, a.status as astatus, a.mch_id, a.free_or_not, a.user_id, a.add_time, a.expiry_time, a.type, b.NAME, a.store_id, b.activity_type, b.money, b.discount, d.mobile, d.user_id as duserid, c.sNo, CAST( d.user_name AS CHAR ) user_name, d.headimgurl, e.STATUS, ROW_NUMBER() over(partition by a.user_id) AS top FROM lkt_coupon AS a LEFT JOIN lkt_coupon_activity AS b ON a.hid = b.id LEFT JOIN lkt_coupon_sno AS c ON c.coupon_id = a.id AND c.recycle = 0 LEFT JOIN lkt_user AS d ON a.user_id = d.user_id LEFT JOIN lkt_order AS e ON c.sNo = e.sNo ) AS a where a.store_id = #{store_id} and a.status = 0 and a.top <2 and a.recycle=0 AND a.astatus = #{status} AND a.hid = #{hid} AND a.mch_id = #{mch_id} AND a.sNo like concat('%',#{likeOrderno},'%') AND a.activity_type = #{activityType} and a.user_name like concat('%',#{user_name},'%') AND( a.sNo like concat('%',#{userName},'%') or a.duserid like concat('%',#{userName},'%') or a.mobile like concat('%',#{userName},'%'))
AND( a.sNo like concat('%',#{keyWord},'%') or a.user_name like concat('%',#{keyWord},'%') or a.id like concat('%',#{keyWord},'%'))
#{type,jdbcType=INTEGER}
#{id,jdbcType=INTEGER}
AND a.type = #{couponType} AND a.user_id = #{user_id} AND a.type != #{notCouponType} AND a.free_or_not = #{free_or_not}
a.add_time ${add_time_sort}
LIMIT #{page},#{pageSize}

select count(1) from lkt_coupon as a
where a.store_id = #{store_id}
and a.status = #{status}
and a.recycle = #{recycle}
and a.user_id = #{user_id}
and a.hid = #{hid}


        #{type,jdbcType=INTEGER}

